#include<bits/stdc++.h>
using namespace std;
priority_queue<int,vector<int>,greater<int> > q;
int n,k,maxx=-1;
int main()
{
    cin>>n>>k;
    for(int i=1;i<=n;i++)
    {
        int t;
        cin>>t;
        q.push(t);
    }
    for(int i=1;i<=n&&i<=k;i++)
    {
        if(maxx==q.top()) k++;
        maxx=q.top();
        q.pop();
    }
    if(k>n) cout<<"NO RESULT";
    else cout<<maxx;
    return 0;
}
